import { Router, Request, Response } from 'express';
import { prisma } from '../index';
import { requireAuth } from '../middleware/auth.middleware';
import { calculateInitialPools } from '../services/lmsr.service';

const router = Router();

// Endpoint for Admins to view all Pending Events generated by the Gemini Agent
router.get('/pending', requireAuth, async (req: Request, res: Response) => {
  try {
    const events = await prisma.event.findMany({
      where: { status: 'PENDING' },
      orderBy: { createdAt: 'desc' }
    });
    res.json(events);
  } catch(err: any) {
    res.status(500).json({ error: err.message });
  }
});

// Endpoint to Approve a Pending event, resolving it into an ACTIVE tradeable market
router.post('/approve/:id', requireAuth, async (req: Request, res: Response): Promise<any> => {
  try {
    const { id } = req.params;
    
    const event = await prisma.event.findUnique({ where: { id } });
    if (!event || event.status !== 'PENDING') {
      return res.status(404).json({ error: 'Valid Pending event not found' });
    }

    // Set initial liquidity depths matching the suggested probability so trading starts efficiently
    const initPools = calculateInitialPools(event.suggestedProbability ?? 50.0);

    const activeEvent = await prisma.event.update({
      where: { id },
      data: {
        status: 'ACTIVE',
        poolYes: initPools.yesPool,
        poolNo: initPools.noPool,
        probability: event.suggestedProbability ?? 50.0,
      }
    });

    // We can emit a websocket event here informing users of a new market globally!
    console.log(`[Admin] Activating new global market: ${activeEvent.question}`);
    res.json({ success: true, event: activeEvent });

  } catch(err: any) {
    res.status(500).json({ error: err.message });
  }
});

// Endpoint to Reject an LLM generation
router.post('/reject/:id', requireAuth, async (req: Request, res: Response): Promise<any> => {
  try {
    const { id } = req.params;
    await prisma.event.update({
      where: { id },
      data: { status: 'REJECTED' }
    });
    res.json({ success: true });
  } catch(err: any) {
    res.status(500).json({ error: err.message });
  }
});

export default router;
